const input = $input.first() ? $input.first().json : {};
const body = (input && input.body) || input || {};
if (!body.user_id) throw new Error('user_id obrigatorio');
if (!body.company_name) throw new Error('company_name obrigatorio');
return [{ json: {
  user_id: String(body.user_id),
  company_name: String(body.company_name),
  ano_base: parseInt(body.ano_base, 10) || null,
  ano_previsao: parseInt(body.ano_previsao, 10) || (new Date().getFullYear() + 1)
} }];

const items = $input.all().map(i => i.json);
const xlsx = items.filter(f => {
  const name = (f.name || '').toLowerCase();
  const mime = (f.mimeType || '').toLowerCase();
  return name.endsWith('.xlsx') || mime.includes('spreadsheetml') || mime.includes('vnd.google-apps.spreadsheet');
});
if (xlsx.length === 0) throw new Error('Nenhuma planilha encontrada na pasta do Google Drive.');
xlsx.sort((a, b) => new Date(b.modifiedTime || b.createdTime || 0) - new Date(a.modifiedTime || a.createdTime || 0));
const latest = xlsx[0];
return [{ json: { file_id: latest.id, file_name: latest.name, modified_time: latest.modifiedTime || null } }];

// ===== BUILD ROWS: transforma o xlsx em linhas para o Supabase =====
const params = $('Validate Input').first().json;
const userId = params.user_id;
const company = params.company_name;
const anoPrev = Number(params.ano_previsao) || (new Date().getFullYear() + 1);
const picked = $('Pick Latest XLSX').first().json;

function rowsOf(node){ try { return $(node).all().map(i => i.json).filter(Boolean); } catch (e) { return []; } }
const baseRows = rowsOf('Extract Base');
const orcRows = rowsOf('Extract Orcamento');

const norm = (s) => (s === undefined || s === null) ? '' : String(s).trim();
const num = (v) => {
  if (typeof v === 'number') return isNaN(v) ? 0 : v;
  if (v === undefined || v === null || v === '') return 0;
  const s = String(v).trim().split(' ').join('').split(String.fromCharCode(160)).join('').replace(',', '.');
  const n = parseFloat(s); return isNaN(n) ? 0 : n;
};
const flat = (s) => String(s).toLowerCase().split(' ').join('').split(String.fromCharCode(160)).join('');
function keyFor(obj, names){
  const keys = Object.keys(obj || {});
  for (const n of names){ const k = keys.find(h => flat(h) === flat(n)); if (k) return k; }
  for (const n of names){ const k = keys.find(h => String(h).toLowerCase().includes(n.toLowerCase())); if (k) return k; }
  return null;
}
function uuidv4(){ return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c){ const r = Math.random()*16|0, v = c === 'x' ? r : (r & 0x3 | 0x8); return v.toString(16); }); }

const batchId = uuidv4();

// ---- historico_vendas (todas as linhas validas, qualquer ano) ----
const historico = [];
if (baseRows.length){
  const s = baseRows[0];
  const bk = {
    item: keyFor(s, ['Item','SKU']), regional: keyFor(s, ['Regional']),
    mes: keyFor(s, ['Mes','Mês']), ano: keyFor(s, ['Ano']),
    qtd: keyFor(s, ['Quantidade','Qtd','Qtde']), valor: keyFor(s, ['Valor','Faturamento']),
    descricao: keyFor(s, ['Descricao','Descrição']), nomeReg: keyFor(s, ['Nome Regional','Nome_Regional']),
    tipo: keyFor(s, ['Tipo Mercado','Tipo_Mercado','Mercado'])
  };
  for (const row of baseRows){
    const item = norm(bk.item ? row[bk.item] : '');
    const regional = norm(bk.regional ? row[bk.regional] : '');
    if (!item || !regional) continue;
    const mes = parseInt(bk.mes ? row[bk.mes] : '', 10);
    const ano = parseInt(bk.ano ? row[bk.ano] : '', 10);
    if (!(mes >= 1 && mes <= 12)) continue;
    if (!(ano >= 2020 && ano <= 2030)) continue;
    historico.push({
      user_id: userId, company_name: company, ano, mes, item,
      descricao: bk.descricao ? norm(row[bk.descricao]) : '', regional,
      nome_regional: bk.nomeReg ? norm(row[bk.nomeReg]) : '',
      tipo_mercado: bk.tipo ? norm(row[bk.tipo]) : '',
      quantidade: num(bk.qtd ? row[bk.qtd] : 0),
      valor: bk.valor ? num(row[bk.valor]) : null,
      upload_batch_id: batchId
    });
  }
}

// ---- orcamento (deduplicado por item||regional) ----
const orcamento = [];
if (orcRows.length){
  const s = orcRows[0];
  const ok = {
    item: keyFor(s, ['Item','SKU']), regional: keyFor(s, ['Regional']),
    descricao: keyFor(s, ['Descricao','Descrição']), nomeReg: keyFor(s, ['Nome Regional','Nome_Regional']),
    orc: keyFor(s, ['Orcamento Total','Orçamento Total','Orcamento','Orçamento','Total','Budget'])
  };
  const seen = new Set();
  for (const row of orcRows){
    const item = norm(ok.item ? row[ok.item] : '');
    const regional = norm(ok.regional ? row[ok.regional] : '');
    if (!item || !regional) continue;
    const key = item + '||' + regional; if (seen.has(key)) continue; seen.add(key);
    orcamento.push({
      user_id: userId, company_name: company, ano: anoPrev, item, regional,
      descricao: ok.descricao ? norm(row[ok.descricao]) : '',
      nome_regional: ok.nomeReg ? norm(row[ok.nomeReg]) : '',
      orcamento_total: num(ok.orc ? row[ok.orc] : 0), upload_batch_id: batchId
    });
  }
}

if (historico.length === 0) {
  throw new Error('Nenhuma linha valida encontrada na Base_Historica_de_Vendas.');
}

const anos = [...new Set(historico.map(h => h.ano))].sort();
const snapshot = {
  user_id: userId, company_name: company, batch_id: batchId,
  file_name: picked.file_name || null, file_id: picked.file_id || null,
  modified_time: picked.modified_time || null,
  ano_base: anos.length ? anos[anos.length - 1] : null,
  total_rows: historico.length, total_orcamento: orcamento.length,
  status: 'processando', is_atual: false
};
return [{ json: { batch_id: batchId, company_name: company, snapshot, historico, orcamento, anos } }];
